demos.desktop:
render(() => {
    const [count, setCount] = React.useState(0);
    const [buttonElement, setButtonElement] = React.useState(null);

    const label = {
        0: 'Показать поповер снизу',
        1: 'Показать поповер сверху',
        2: 'Показать слева',
        3: 'Показать справа',
        4: 'Скрыть',
    };

    const position = {
        1: 'bottom',
        2: 'top',
        3: 'left',
        4: 'right',
    };

    // updatePopover - ref, который хранит функцию, с помощью которой можно обновить положение поповера
    const updatePopover = React.useRef();

    const onClick = () => {
        setCount((count) => count + 1);

        if (updatePopover.current) {
            // Обновляем положение поповера
            updatePopover.current();
        }
        if (count === 4) {
            setCount(0);
        }
    };

    const handleButtonRef = (node) => {
        if (count !== 0) {
            setButtonElement(node);
        }
    };
    const popoverChildren = (
        <>{count !== 0 && <div style={{ padding: '15px', width: '156px' }}>Popover</div>}</>
    );

    return (
        <div
            style={{
                width: '700px',
                height: '300px',
                display: 'flex',
                justifyContent: 'center',
                alignItems: 'center',
            }}
        >
            <Popover
                anchorElement={buttonElement}
                useAnchorWidth={true}
                position={position[count]}
                open={count !== 0}
                update={updatePopover}
                offset={[0, 4]}
            >
                {popoverChildren}
            </Popover>

            <Button size={48} ref={handleButtonRef} onClick={onClick}>
                {label[count]}
            </Button>
        </div>
    );
});

